actions.script:
def lc = ec.entity.find("trade.importlc.ImportLetterOfCredit").condition("instrumentId", instrumentId).one()
def actualFromState = fromStateId ?: lc?.businessStateId ?: instrument?.businessStateId

if (!actualFromState || actualFromState == toStateId) return

def transition = ec.entity.find("moqui.basic.StatusFlowTransition")
    .condition([statusId: actualFromState, toStatusId: toStateId, statusFlowId: 'ImportLcDefault'])
    .one()

if (!transition) {
    ec.message.addError("Invalid Business State transition from ${actualFromState} to ${toStateId} for Instrument ${instrumentId}")
}

def X_PATTERN = /^[A-Za-z0-9\/ \-\?\:\(\)\.\,\'\+\r\n]*$/
def Z_PATTERN = /^[A-Za-z0-9\.\,\-\(\)\/\=\'\+\:\? \!\#\&\*<>\;\@\r\n]*$/
def BIC_PATTERN = /^[A-Z0-9]{8}$|^[A-Z0-9]{11}$/

def addError = { fieldName, message, type ->
    errors.add([fieldName: fieldName, message: message, violationType: type])
}

def validateXCharset = { fieldName, value ->
    if (!value) return
    value.toString().eachWithIndex { ch, idx ->
        if (!(ch ==~ /[A-Za-z0-9\/ \-\?\:\(\)\.\,\'\+\r\n]/)) {
            addError(fieldName, "Invalid X charset character '${ch}' at position ${idx+1}", "CHARSET")
        }
    }
}
def validateZCharset = { fieldName, value ->
    if (!value) return
    value.toString().eachWithIndex { ch, idx ->
        if (!(ch ==~ /[A-Za-z0-9\.\,\-\(\)\/\=\'\+\:\? \!\#\&\*<>\;\@\r\n]/)) {
            addError(fieldName, "Invalid Z charset character '${ch}' at position ${idx+1}", "CHARSET")
        }
    }
}
def validateBic = { fieldName, value ->
    if (!value) return
    if (!(value.toString() ==~ BIC_PATTERN)) {
        addError(fieldName, "SWIFT BIC must be exactly 8 or 11 characters", "BIC")
    }
}
def validateLineLimit = { fieldName, value, maxLines ->
    if (!value) return
    def lines = value.toString().split('\n')
    if (lines.size() > maxLines) {
        addError(fieldName, "Exceeds maximum ${maxLines} lines", "FORMAT")
    }
}
def validateReference = { fieldName, value ->
    if (!value) return
    if (value.toString().length() > 16) {
        addError(fieldName, "Reference exceeds 16-character maximum", "LENGTH")
    }
    if (value.toString().startsWith('/') || value.toString().endsWith('/') || value.toString().contains('//')) {
        addError(fieldName, "Reference contains illegal slash sequence (//, leading, or trailing)", "FORMAT")
    }
}

if (entityType == "TradeInstrument") {
    def inst = ec.entity.find("trade.TradeInstrument").condition("instrumentId", entityId).one()
    if (inst) {
        validateReference("transactionRef", inst.transactionRef)
    }
} else if (entityType == "ImportLetterOfCredit") {
    def lc = ec.entity.find("trade.importlc.ImportLetterOfCredit").condition("instrumentId", entityId).one()
    if (lc) {
        validateXCharset("portOfLoading", lc.portOfLoading)
        validateXCharset("portOfDischarge", lc.portOfDischarge)
        validateXCharset("goodsDescription", lc.goodsDescription)
        validateXCharset("documentsRequired", lc.documentsRequired)
        validateXCharset("applicantName", lc.applicantName)
        validateXCharset("beneficiaryName", lc.beneficiaryName)

        validateLineLimit("applicantName", lc.applicantName, 4)
        validateLineLimit("beneficiaryName", lc.beneficiaryName, 4)

        validateBic("issuingBankBic", lc.issuingBankBic)
        validateBic("advisingBankBic", lc.advisingBankBic)

        // Mandatory Fields for MT700
        if (!lc.lcTypeEnumId) addError("lcTypeEnumId", "Required (SWIFT Tag 40A)", "MANDATORY")
        if (!lc.availableByEnumId) addError("availableByEnumId", "Required (SWIFT Tag 41a)", "MANDATORY")
        if (!lc.confirmationEnumId) addError("confirmationEnumId", "Required (SWIFT Tag 49)", "MANDATORY")

        // Mutual Exclusion: Tolerance vs Max Credit Amount
        if (lc.maxCreditAmountFlag == 'Y' && (lc.tolerancePositive || lc.toleranceNegative)) {
            addError("maxCreditAmountFlag", "Tolerance fields and Max Credit Amount Flag are mutually exclusive", "LOGIC")
        }

        // Conditional: Usance fields
        if (lc.tenorTypeId == 'USANCE' && (!lc.usanceDays || !lc.usanceBaseDate)) {
            if (!lc.usanceDays) addError("usanceDays", "Required for USANCE tenor", "CONDITIONAL")
            if (!lc.usanceBaseDate) addError("usanceBaseDate", "Required for USANCE tenor", "CONDITIONAL")
        }

        // Mutual Exclusion: Shipment Period vs Latest Shipment Date
        if (lc.shipmentPeriodText && lc.latestShipmentDate) {
            addError("shipmentPeriodText", "Shipment Period and Latest Shipment Date are mutually exclusive", "LOGIC")
        }
    }
} else if (entityType == "TradeDocumentPresentation") {
    def pres = ec.entity.find("trade.importlc.TradeDocumentPresentation").condition("presentationId", entityId).one()
    if (pres) {
        validateZCharset("chargesDeducted", pres.chargesDeducted)
        validateZCharset("senderToReceiverPresentationInfo", pres.senderToReceiverPresentationInfo)

        validateLineLimit("chargesDeducted", pres.chargesDeducted, 6)
        validateLineLimit("senderToReceiverPresentationInfo", pres.senderToReceiverPresentationInfo, 6)
    }
} else if (entityType == "ImportLcAmendment") {
    def amd = ec.entity.find("trade.importlc.ImportLcAmendment").condition("amendmentId", entityId).one()
    if (amd) {
        validateZCharset("amendmentNarrative", amd.amendmentNarrative)
    }
}
